#!/usr/bin/env node
/**
 * Generates index.js for the @gravity-ui/icons shim by re-exporting every
 * icon from the real package via subpath imports (which include the .js
 * extension that Node's strict ESM resolver requires).
 *
 * Run from the web/ directory: node vendor/gravity-ui-icons-shim/generate.mjs
 */
import { readdirSync, writeFileSync } from "node:fs";
import { dirname, join } from "node:path";
import { fileURLToPath } from "node:url";

const __dirname = dirname(fileURLToPath(import.meta.url));
const ICONS_ROOT = join(__dirname, "..", "..", "node_modules", "@gravity-ui", "icons-real");

const files = readdirSync(ICONS_ROOT).filter(
  (f) => f.endsWith(".js") && !f.startsWith(".") && f !== "index.js",
);

const lines = [
  "// AUTO-GENERATED by generate.mjs. Do not edit by hand.",
  "// Re-exports every @gravity-ui/icons icon as a named export so that both",
  "// HeroUI Pro and our own components can do",
  "//   import { GripHorizontal, Plus, Layers } from '@gravity-ui/icons'",
  "// while still going through Node's strict ESM resolver.",
  "",
];

for (const file of files.sort()) {
  const name = file.replace(/\.js$/, "");
  lines.push(`export { default as ${name} } from "@gravity-ui/icons-real/${name}.js";`);
}

writeFileSync(join(__dirname, "index.js"), `${lines.join("\n")}\n`);
console.log(`Wrote shim with ${files.length} icons.`);
